CRTP bir sinifin özünü şablon parametri kimi törəmə sinifə ötürməsi ilə işləyən dizayn modelidir. Bu, statik polimorfizmə imkan verir və virtual funksiyaların performans itkisindən qaçır. Sintaksis:
template <typename Derived>
class Base {
  // Metodlar
};
class Derived : public Base<Derived> {
  // Törəmə sinif
};

content.code:
#include <iostream>

template <typename Derived>
class Base {
public:
  void interface() {
    static_cast<Derived*>(this)->implementation();
  }
};

class Derived : public Base<Derived> {
public:
  void implementation() {
    std::cout << "Derived implementation\n";
  }
};

int main() {
  Derived obj;
  obj.interface();
  return 0;
}
// Output:
// Derived implementation

#include <iostream>

template <int N>
struct Factorial {
  static const int value = N * Factorial<N - 1>::value;
};

template <>
struct Factorial<0> {
  static const int value = 1;
};

int main() {
  std::cout << "Factorial of 5: " << Factorial<5>::value << std::endl;
  return 0;
}
// Output:
// Factorial of 5: 120

